mutationFn: async () => {
  const validation = validatePassword(newPassword);
  if (!validation.valid) {
    throw new Error(validation.reason || 'Enter a stronger password.');
  }

  if (newPassword !== confirmPassword) {
    throw new Error('New passwords do not match.');
  }

  const supabaseReady = isSupabaseConfigured();

  // ── Path 1: Backend proxy (when Supabase not configured) ──
  if (!supabaseReady && proxyAccessToken) {
    console.log('[ResetPassword] Updating password via backend proxy');
    const proxyResult = await proxyUpdatePassword(proxyAccessToken, newPassword);
    if (!proxyResult.ok) {
      throw new Error(proxyResult.error || 'Password update failed through the backend.');
    }
    return { email: resolvedEmail };
  }

  // ── Path 2: Direct Supabase ──
  const { data: sessionData } = await supabase.auth.getSession();
  const session = sessionData.session;
  if (!session) {
    throw new Error('Password recovery session expired. Request a new reset link and try again.');
  }

  const nextEmail = session.user.email?.trim().toLowerCase() || resolvedEmail;
  console.log('[ResetPassword] Updating password for:', nextEmail || session.user.id);
  const { error } = await supabase.auth.updateUser({ password: newPassword });
  if (error) {
    throw new Error(error.message || 'Supabase rejected the password update.');
  }

  return { email: nextEmail };
},

